INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'YKH-TB', 'ワイヤー支持金具', '振れ止め又は、メッセンジャーワイヤー、ミラックラダーHを吊りボルト等で支持する場合に使用します。許容静荷重: 980N(100kgf)。最大ワイヤー保持力: 98N(10kgf)。締付トルク: 7.84N・m(80kgf-cm)。電気亜鉛めっき仕様, 適合ワイヤー径: φ4.8~φ9.6 (メッセンジャーワイヤー: 14sq~55sq)', 630, 'https://dummyimage.com/200x200/cccccc/000.png&text=YKH-TB', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 50, 88, 22);
