INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SRM6-ET', 'アースボンド金具', 'ミラックラダーHと建物の電気的接続に使用します。アプセットボルト(M6×15)付。アースボンド線への接続。電気亜鉛めっき仕様, スチール製, RoHS対応。適合ワイヤー: φ5, メッセンジャーワイヤー: 14sq, 適合ケーブル: φ6.3, φ3.5, M5, φ4.5', 450, 'https://dummyimage.com/200x200/cccccc/000.png&text=SRM6-ET', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 48.5, 45, 34);
