INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SGM', '形鋼金具 H・L形鋼用', 'ループボルトをH形鋼等への固定に使用します。サポート金具が取り付けられます。(品番: SGMH)。許容静荷重: 294N(30kgf), 981N(100kgf)。M8×45六角ボルト(くぼみ先)。適合寸法(A): H・L形鋼(鋼材厚30mm迄)', 340, 'https://dummyimage.com/200x200/cccccc/000.png&text=SGM', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 36, 60, 50);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SGMK', '形鋼金具 H・L形鋼用', '吊りボルトを下げ、ラック・ダクト等の支持に使用します。サポート金具が取り付けられます。許容静荷重: 2450N(250kgf), 686N(70kgf)。M10×55六角ボルト。RoHS対応。高強度タイプ, 適合寸法(A): H・L形鋼(鋼材厚30mm迄)', 1070, 'https://dummyimage.com/200x200/cccccc/000.png&text=SGMK', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 60, 88, 64);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SGMH', '形鋼金具用サポート金具 H形鋼用 ボルト無', '鋼材に取り付けた形鋼金具を振動に対して、外れにくくするための補強金具です。寸切ボルト(W3/8)。電気亜鉛めっき仕様。RoHS対応。適合: 形鋼金具(SGM・SGMK)', 620, 'https://dummyimage.com/200x200/cccccc/000.png&text=SGMH', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 42, 35, 79);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KM-6A', '垂直母線クランプ', '耐衝撃、耐薬品樹脂製。M6×22mm(六角穴付ボルト)。垂直母線クランプ引張強度: ①本体ズレ荷重 2.64kN(269kgf), ②ケーブル用係止部破壊荷重 2.00kN(204kgf), ③接地線用係止部破壊荷重 735N(75kgf)。適合ケーブル: 600VCV3C-38mm²~600VCV3C-150mm², 600V CVT38mm²~600V CVT100mm², JIS G3537 亜鉛めっき鋼より線2号1種(7/2.60,外径7.8mm,断面37.2mm²), 適合接地母線(仕上り外径13迄)', 3790, 'https://dummyimage.com/200x200/cccccc/000.png&text=KM-6A', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 44, 100, 44);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KS-6A', 'クランプスペーサ', '2個1組(ゴム製)。垂直母線クランプの最小適合ケーブル以下の細いケーブルを固定する場合に使用します。適合ケーブル: 600VCV3C-8mm²~600VCV3C-22mm²', 750, 'https://dummyimage.com/200x200/cccccc/000.png&text=KS-6A', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 20, 13, 90);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'CH-20', 'ローラーハンガー (ローラー付ケーブルハンガー)', 'ケーブルハンガーにローラーが付きました。ケーブル延線・架線作業が同時にできます。面倒なハシゴ等を使う必要がなく、簡単で安全に取り付けられます。プラスチック製ですから、絶縁性は抜群です。自家用電気構内架線・通信架線に便利です。作業の省力とスピードアップに是非お使いください。(販売中止品)。適合ケーブル: φ10~φ20, 適合ワイヤー: φ3~φ8', 430, 'https://dummyimage.com/200x200/cccccc/000.png&text=CH-20', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
