INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'ZT-6P3YL', 'OAタップ 抜け止め 6P', 'OAフロア内からOAフロア上に引き出して使用してください。接地型・接地無の一般プラグが使用できます。15A 125V, 電源コード3m, 刃受部は熱に強く、外ケースは割れにくい二重構造です。机や壁面に吊り下げられるフック付です。より線、圧着端子の全てが接続できるアースターミナルを採用しました。通電確認のできるLEDランプ付。', 13100, 'https://dummyimage.com/200x200/cccccc/000.png&text=ZT-6P3YL', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 50, 29, 260);
