INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MTKB-S18', 'タイカブラック® 耐火シート (メッシュ無)', '配管に巻き付けるだけの簡単施工です! 中空壁の場合、開口補強が不要です。床貫通の場合は、施工が床上から可能です。シートだけのシンプル部材! 壁・床のどちらにも使用できる万能な防火部材です。軽量なので持ち運びにも便利です。施工がシンプルなので仕上がりが安定しています! シート状の為、規定量を確実に施工できます。2倍以上にふくらみ、延焼を防止! 300℃以上の熱を受けると、2倍以上にふくらみ延焼を防止します。加工が少なく、廃材、ホコリもほとんど出ません!', 970, 'https://dummyimage.com/200x200/cccccc/000.png&text=MTKB-S18', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 64, 184, 1);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FPK-S', '防火キット', 'はめ込むだけのワンタッチ装着。さや管(CD管・PF管)及び保温材付配管にも簡単に取付可能です。配管1本あたり防火キット1個で施工可能(部屋内側又は共用部側のいずれかに設置)です。壁仕上げ面より10mm まで突き出しが可能(床施工の場合を除きます)となり、穴埋め時の位置調整が簡単となりました。配管を横方向に並べる場合は、他製品のように一定間隔をあける必要が無 く、防火キット同士が接触していても差し支えありません。(縦方向に段重ねとなる場合は、上下の配管の間隔を10mm 以上確保してください)多種にわたる配管に対応。従来品の防火キットFPP と比べると、肉厚-0.5mm.全長-10mm のサイズダウンとなり、また金属スリーブも廃止することによりさらなる小型化、軽量化を実施しました。新仕様の壁にも対応。', 1450, 'https://dummyimage.com/200x200/cccccc/000.png&text=FPK-S', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 24, 24, 19);
