INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MTKB-AC50', 'タイカブラック® パテエース®(丸穴キット)', 'バックアップスリーブを開口にはめて、パテを充填するだけの簡単施工! 1開口につき1セット! 無駄の出ない使いきりキット。300℃以上の熱を受けると4倍以上にふくらみ、延焼を防止します! パテエースは粘土状なのでムラなく隙間に充填できます。パテエースは硬化しないので再施工も可能です。空調配管だけでなく、ケーブル、電線管、給排水管等にも使用できます。パテエース×1個 バックアップスリーブ×1個。認定シール1枚付。', 2170, 'https://dummyimage.com/200x200/cccccc/000.png&text=MTKB-AC50', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
