INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MTKB-RF10', 'タイカブラック®ロール', '冷凍倉庫・低温設備の大口径配管の区画貫通防火処理に最適なロールタイプの防火部材。配管に巻きつけてバインド線で固定。クルクル引き出し可能な段ボールケース入。ロール本体：幅155mm、厚さ3.5mm、長さ10m巻。バインド線：長さ30m巻。認定シール16枚付。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MTKB-RF10', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 155, NULL, 3.5);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MTKB-R21K15', '壁用鋼製スリーブ', '壁・中空壁共通部材。開口部に鋼製スリーブを施工し、配管と鋼製スリーブのすき間にロックウールを差し込む。重ね代を調整することで開口に合わせた設置が可能。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MTKB-R21K15', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 150, 90, 140);
