INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'TK-TP', '耐火パテ', '不乾性・耐火パテ。「自己消火性あり」。防火区画を貫通する鋼製電線管、CD管、PF管の端部シール材として使用。グレー色。1kg入。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=TK-TP', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
