INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MTKB-SP', 'タイカブラック® シールパテ', '不乾性・電気絶縁性パテ。「自己消火性なし」。防火区画を貫通する配管(CD管・PF管等)端部に使用。電気配線のシール材やエアコンパテとして使用。ポリブテン樹脂及び合成樹脂接着剤を基材としたシール材。グレー色。1kg入。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MTKB-SP', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MTKB-FP', '不燃パテ', '国土交通大臣認定 NM-4224(不燃)。不燃配管の防火区画貫通部埋め戻し材に最適。不燃材料による内装制限箇所にも使用可能。硬化型でモルタル同様に配管等を強固に固定。隙間に注入しやすいハンドタイプ。グレー色。水溶性。500g入。', 1760, 'https://dummyimage.com/200x200/cccccc/000.png&text=MTKB-FP', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MTKB-WS', '防水スプレー', '不燃パテ(TK-TP)を一時的に防水するためのスプレー。180ml入。', 3190, 'https://dummyimage.com/200x200/cccccc/000.png&text=MTKB-WS', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FH-125F', 'フリーホルソー®(深型)', '天井、壁材の穴あけ用。シャンク径φ10mm。切削径φ47~125mm。耐火壁、遮音壁に対応できる切り込み深さ45mm。小型軽量で取り回しが容易。深さ調整にロック機構付。壁面開口作業時の切粉落下防止用ダストカバー付き。せっこうボード専用。', 31900, 'https://dummyimage.com/200x200/cccccc/000.png&text=FH-125F', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
