INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'MS265a', '太陽電池モジュールMODULUS ブラックモデル 標準タイプ', '暑さに強くハイパワーなN型バックコンタクト太陽電池モジュール。N型バックコンタクト方式で従来品に比べモジュール公称最大出力が最大14%UP。太陽電池モジュール『HIT®』と同等レベルの出力温度係数-0.26%/℃により夏場でもしっかり発電。受光面の配線を裏面に集約することでスッキリとした外観を実現。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MS265a', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'MS130α', '太陽電池モジュールMODULUS ブラックモデル ハーフタイプ', '暑さに強くハイパワーなN型バックコンタクト太陽電池モジュール。N型バックコンタクト方式で従来品に比べモジュール公称最大出力が最大14%UP。太陽電池モジュール『HIT®』と同等レベルの出力温度係数-0.26%/℃により夏場でもしっかり発電。受光面の配線を裏面に集約することでスッキリとした外観を実現。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MS130%CE%B1', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'MS470α', '太陽電池モジュールMODULUS ブラックモデル 大型タイプ', '暑さに強くハイパワーなN型バックコンタクト太陽電池モジュール。N型バックコンタクト方式で従来品に比べモジュール公称最大出力が最大14%UP。太陽電池モジュール『HIT®』と同等レベルの出力温度係数-0.26%/℃により夏場でもしっかり発電。受光面の配線を裏面に集約することでスッキリとした外観を実現。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MS470%CE%B1', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'nessum™対応PLCアダプター', 'nessum™対応PLCアダプター(PoE給電)(LAN変換)', 'PoE給電機能を搭載し、LANケーブル1本でPoE機器と接続。電源確保が難しい場所でもLANケーブルで電力供給が可能。PoE対応のネットワークカメラやアクセスポイントの増設が容易に。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=nessum%E2%84%A2%E5%AF%BE%E5%BF%9CPLC%E3%82%A2%E3%83%80%E3%83%97%E3%82%BF%E3%83%BC', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), '家具用埋込 充電用USBコンセント 1ポート(最大60W) (USB-C) (リード線付)', '家具・器具用のUSBコンセント', '1ポートで最大60Wの出力を実現。コネクタ挿抜3万回の耐久性で抜き差しの多い場所でも安心。USB-PD対応の最大60Wでノートパソコンの充電が可能。カラーバリエーション：セラミックホワイト、グレー、ブラック。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=%E5%AE%B6%E5%85%B7%E7%94%A8%E5%9F%8B%E8%BE%BC%20%E5%85%85%E9%9B%BB%E7%94%A8USB%E3%82%B3%E3%83%B3%E3%82%BB%E3%83%B3%E3%83%88%201%E3%83%9D%E3%83%BC%E3%83%88(%E6%9C%80%E5%A4%A760W)%20(USB-C)%20(%E3%83%AA%E3%83%BC%E3%83%89%E7%B7%9A%E4%BB%98)', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'フル2線式リモコンスイッチ(アドバンス形)', '多重伝送 フル2線式リモコン:スイッチ(アドバンス形)', '空間に溶け込むアドバンスシリーズのフル2線式リモコンスイッチ新登場。幅広く活用できるマットホワイト/マットグレー/マットブラックの3色を展開。スイッチのLED色を従来の赤/緑に対し、赤/白に変更。専用の調光スイッチが無くなり、一般のリモコンスイッチを設定で調光スイッチ化が可能。スマホと連携することにより、小空間の操作や複雑な照明操作も可能なBluetooth®でつながるスマートデバイス対応のスイッチもラインアップ。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=%E3%83%95%E3%83%AB2%E7%B7%9A%E5%BC%8F%E3%83%AA%E3%83%A2%E3%82%B3%E3%83%B3%E3%82%B9%E3%82%A4%E3%83%83%E3%83%81(%E3%82%A2%E3%83%89%E3%83%90%E3%83%B3%E3%82%B9%E5%BD%A2)', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'VL-SWE720シリーズ/SVE720シリーズ', 'スマホで「外でもドアホン」', 'AIを活用して防犯強化。安心・便利なくらしをスタイリッシュデザインで実現。AIが顔を認証し自動で来訪者応対。AI人検知で自宅前を見守る。ワイヤレスモニター子機背面に緊急時用の非常ボタンを搭載。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=VL-SWE720%E3%82%B7%E3%83%AA%E3%83%BC%E3%82%BA%2FSVE720%E3%82%B7%E3%83%AA%E3%83%BC%E3%82%BA', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'Clouge SQUARE', 'マンションインターホンシステム Iシリーズ Clouge SQUARE', '省施工・省人化により施工業者の人手不足問題を解消。消防検査前に管理室親機で火災信号の入力結果を確認可能。エントランスに人を配置せずに親機からロビーインターホンの通話テストが可能。ロビーインターホンのパネル取り外し不要で画面上から施工設定が可能。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=Clouge%20SQUARE', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'Clouge', 'マンションインターホンシステム Iシリーズ Clouge', '省施工・省人化により施工業者の人手不足問題を解消。消防検査前に管理室親機で火災信号の入力結果を確認可能。エントランスに人を配置せずに親機からロビーインターホンの通話テストが可能。ロビーインターホンのパネル取り外し不要で画面上から施工設定が可能。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=Clouge', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'ハーフカット電線管', 'ハーフカット電線管', 'ハーフサイズ(長さ1.83m*)の電線管で現場での作業性が向上し、省施工に貢献。半分の長さで現場での作業性向上。軽トラックやワンボックスカーで運搬でき一人でも持ち運び可能。JIS適合品 (鋼製:JIS C8305 / SUS:JIS C 861-21)。種類：鋼製電線管 ねじなし電線管E、ステンレス電線管 ねじなしシリーズ、ステンレス電線管 厚鋼ねじなしシリーズ。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=%E3%83%8F%E3%83%BC%E3%83%95%E3%82%AB%E3%83%83%E3%83%88%E9%9B%BB%E7%B7%9A%E7%AE%A1', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), '丸型露出ボックス(0方出)', '丸型露出ボックス', '急な配管変更にも対応。「1個あれば、安心・便利」な新しいボックス。丸型は1~4方出、角型は1~2方出の兼用で、効率的な在庫管理が可能。ダブルノックアウト仕様で、2つの呼び開口の選択・組み合わせが可能。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=%E4%B8%B8%E5%9E%8B%E9%9C%B2%E5%87%BA%E3%83%9C%E3%83%83%E3%82%AF%E3%82%B9(0%E6%96%B9%E5%87%BA)', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
