INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'FLEXIID smart', 'HEMS対応住宅分電盤 FLEXIID smart(フレキシード スマート)', '空間の可能性を広げる、自由自在な分電盤。空間に溶け込むデザインで突き付け設置が可能。計測アダプタを搭載。AiSEGとの連携で電力の見える化が可能。ZEH・創エネ対応/ZEH・省エネ対応 / あんしん機能付/スタンダードまでくらしに合わせたHEMS対応住宅分電盤をご用意。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=FLEXIID%20smart', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'ELSEEV hekia S Mode3', 'Dポール EV・PHEV充電用 ELSEEV hekia S Mode3専用', '建物から離れた場所でも充電スポットの自立設置が可能。シルバーとブラックから選択可能。両面取付タイプで省スペース設置が可能。基礎工事が容易なベースプレート方式もご用意。タイプ：両面取付、ベースプレート方式。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=ELSEEV%20hekia%20S%20Mode3', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'Dポール EV・PHEV充電用 屋外コンセント用(端子台内蔵)', 'Dポール EV・PHEV充電用 屋外コンセント用(端子台内蔵)', 'ポール本体内に端子台を内蔵。広い駐車場での配線の電圧降下対策におすすめ。端子台を内蔵し電圧降下対策が可能。プレート交換のみで充電機器のアップグレードが可能。充電機器変更時の再建柱不要。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=D%E3%83%9D%E3%83%BC%E3%83%AB%20EV%E3%83%BBPHEV%E5%85%85%E9%9B%BB%E7%94%A8%20%E5%B1%8B%E5%A4%96%E3%82%B3%E3%83%B3%E3%82%BB%E3%83%B3%E3%83%88%E7%94%A8(%E7%AB%AF%E5%AD%90%E5%8F%B0%E5%86%85%E8%94%B5)', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'Dポール EV・PHEV充電用 屋外コンセント用(アンカーフレーム用)', 'Dポール EV・PHEV充電用 屋外コンセント用(アンカーフレーム用)', '掘り起こした土を埋め戻して即日施工。コンクリートレスで省施工を実現。廃土処理の削減、コンクリートの管理が不要。2タイプのデザインから選択可能。アンカーフレーム構造で土中埋設の強度を確保。タイプ：スタンダードタイプ、フラットタイプ。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=D%E3%83%9D%E3%83%BC%E3%83%AB%20EV%E3%83%BBPHEV%E5%85%85%E9%9B%BB%E7%94%A8%20%E5%B1%8B%E5%A4%96%E3%82%B3%E3%83%B3%E3%82%BB%E3%83%B3%E3%83%88%E7%94%A8(%E3%82%A2%E3%83%B3%E3%82%AB%E3%83%BC%E3%83%95%E3%83%AC%E3%83%BC%E3%83%A0%E7%94%A8)', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
