INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'MWTY2081', 'リンクプラス用 無線中継器', 'アドバンスシリーズ リンクプラス用 無線中継器。無線アダプタまたは、AiSEGとスイッチの通信を中継します。スイッチまたは、一括OFF発信器とスイッチの通信を中継します。定格電圧: AC100V, 定格周波数: 50Hz/60Hz, 消費電力: 1.5W以下, 使用周囲温度: 0~+40℃ (~90%RH), 質量: 約200g. 通信距離: 障害物の無い場所での水平見通し距離約30m. 使用周波数: 923.7MHz~927.7MHz 全11波中の1波を使用。', 30000, 'https://dummyimage.com/200x200/cccccc/000.png&text=MWTY2081', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', 44, 100, 30);
